import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["modal", "form", "nameField", "emailField", "nameError", "emailError", "submitButton", "modalHeader"]
  static values = {
    url: String,
  }

  show() {
    this.modalTarget.classList.remove('hidden')
    this.modalTarget.setAttribute('aria-hidden', 'false')
    this.nameFieldTarget.focus()
  }

  hide() {
    this.modalTarget.classList.add('hidden')
    this.modalTarget.setAttribute('aria-hidden', 'true')
    this.resetForm()
  }

  cancel() {
    this.hide()
  }

  resetForm() {
    this.formTarget.reset()
    this.nameErrorTarget.classList.add('hidden')
    this.emailErrorTarget.classList.add('hidden')
    this.nameErrorTarget.textContent = ''
    this.emailErrorTarget.textContent = ''
  }

  submit(e) {
  e.preventDefault()

  this.submitButtonTarget.disabled = true
  this.submitButtonTarget.classList.add('opacity-50', 'cursor-not-allowed')

  const formData = new FormData(this.formTarget)
  const userData = {
    name: formData.get('name'),
    email: formData.get('email'),
  }

  fetch(this.urlValue, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Accept': 'text/vnd.turbo-stream.html, application/json',
      'X-CSRF-Token': document.querySelector("[name='csrf-token']").content
    },
    body: JSON.stringify(userData)
  })
    .then(response => {
      if (!response.ok) {
        return response.json().then(err => { throw err })
      }

      const contentType = response.headers.get("Content-Type")
      if (contentType && contentType.includes("text/vnd.turbo-stream.html")) {
        return response.text().then(html => Turbo.renderStreamMessage(html))
      }

      return response.json()
    })
    .then(() => {
      this.hide()
    })
    .catch(error => {
      this.handleErrors(error.errors)
    })
    .finally(() => {
      this.submitButtonTarget.disabled = false
      this.submitButtonTarget.classList.remove('opacity-50', 'cursor-not-allowed')
    })
}


  handleErrors(errors = {}) {
  this.nameErrorTarget.classList.add('hidden')
  this.emailErrorTarget.classList.add('hidden')

  if (errors.name?.length > 0) {
    this.nameErrorTarget.textContent = errors.name.join(', ')
    this.nameErrorTarget.classList.remove('hidden')
  }

  if (errors.email?.length > 0) {
    this.emailErrorTarget.textContent = errors.email.join(', ')
    this.emailErrorTarget.classList.remove('hidden')
  }
}

}
