import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["modal", "nameField", "emailField", "form", "nameError"]
  static values = { url: String }

  connect() {
    this.currentId = null
  }

  edit(event) {
    event.preventDefault()
    const row = event.target.closest("tr")
    this.currentId = row.dataset.userId

    // Populate form fields with the current row's values
    this.nameFieldTarget.value = row.querySelector("td:nth-child(1)").textContent.trim()
    this.emailFieldTarget.value = row.querySelector("td:nth-child(2)").textContent.trim()

    this.clearErrors()
    this.modalTarget.classList.remove("hidden")
  }

  cancel() {
    this.modalTarget.classList.add("hidden")
    this.currentId = null
    this.formTarget.reset()
    this.clearErrors()
  }

  clearErrors() {
    if (this.hasNameErrorTarget) this.nameErrorTarget.classList.add("hidden")
  }

  showError(field, message) {
    const errorTarget = `${field}ErrorTarget`
    if (this[errorTarget]) {
      this[errorTarget].textContent = message
      this[errorTarget].classList.remove("hidden")
    }
  }

  async submit(event) {
    event.preventDefault();

    if (!this.currentId) {
      this.showError('name', 'No user selected');
      return;
    }

    this.clearErrors();

    const urlParams = new URLSearchParams(window.location.search);
    const currentPage = urlParams.get('page') || 1;

    fetch(`${this.urlValue}/${this.currentId}?page=${currentPage}`, {
      method: 'PATCH',
      headers: {
        'X-CSRF-Token': document.querySelector("[name='csrf-token']").content,
        'Content-Type': 'application/json',
        'Accept': 'text/vnd.turbo-stream.html, application/json'
      },
      body: JSON.stringify({
        user: {
          name: this.nameFieldTarget.value
        }
      })
    })
    .then(response => {
      const contentType = response.headers.get('content-type') || '';

      if (response.ok && contentType.includes('text/vnd.turbo-stream.html')) {
        return response.text().then(html => ({ type: 'turbo', html }));
      }

      if (!response.ok && contentType.includes('application/json')) {
        return response.json().then(data => ({ type: 'json', data }));
      }

      if (response.ok) {
        return { type: 'reload' };
      }

      throw new Error('Unexpected response format');
    })
    .then(result => {
      if (result.type === 'turbo') {
        Turbo.renderStreamMessage(result.html);
        this.cancel();
      } else if (result.type === 'json') {
        if (result.data.errors) {
          if (result.data.errors.name) {
            this.showError('name', result.data.errors.name.join(', '));
          } else {
            this.showError('name', 'Failed to update');
          }
        }
      } else if (result.type === 'reload') {
        window.location.reload();
      }
    })
    .catch(error => {
      console.error('Update error:', error);
      this.clearErrors();
      this.showError('name', 'Network error - please try again');
    });
  }
}
