import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["assignManagerModal", "assignManagerModalChosenManager", "assignButton"]

  setSupervisor(event) {
    event.preventDefault();
    const supervisorId = event.currentTarget.dataset.supervisorId;
    const managerId = event.currentTarget.dataset.managerId;
    
    this.assignManagerModalTarget.dataset.supervisorId = supervisorId;
    
    this.showModal();
    
    if (managerId) {
      this.assignManagerModalChosenManagerTarget.value = managerId;
    }
    
    this.updateAssignButtonState();
  }

  allocate(event) {
    if (this.assignButtonTarget.disabled) return;
    event.preventDefault();

    const supervisorId = this.assignManagerModalTarget.dataset.supervisorId;
    const managerIds = [this.assignManagerModalChosenManagerTarget.value];
    const apiUrl = `/admin/supervisors/${supervisorId}/assign_managers`;

    const urlParams = new URLSearchParams(window.location.search);
    const currentPage = urlParams.get('page') || 1;

    fetch(apiUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "text/vnd.turbo-stream.html",
        "X-CSRF-Token": document.querySelector("meta[name='csrf-token']").content
      },
      body: JSON.stringify({ manager_ids: managerIds, page: currentPage })
    })
    .then(async response => {
      if (response.ok) {
        const turboStream = await response.text();
        Turbo.renderStreamMessage(turboStream);
        this.hideModal();
      } else {
        console.error("Turbo Stream request failed:", response.statusText);
      }
    })
    .catch(error => {
      console.error("Error:", error);
    });
  }

  connect() {
    this.assignManagerModalChosenManagerTarget.addEventListener("change", this.updateAssignButtonState.bind(this));
  }

  updateAssignButtonState() {
    const managerSelected = this.assignManagerModalChosenManagerTarget.value !== "";
    
    this.assignButtonTarget.disabled = !managerSelected;
    
    if (managerSelected) {
      this.assignButtonTarget.classList.remove('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
      this.assignButtonTarget.classList.add('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
    } else {
      this.assignButtonTarget.classList.remove('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
      this.assignButtonTarget.classList.add('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
    }
  }

  showModal() {
    this.assignManagerModalTarget.classList.remove("hidden");
  }

  hideModal() {
    this.assignManagerModalTarget.classList.add("hidden");
    this.assignManagerModalChosenManagerTarget.value = "";
    this.updateAssignButtonState();
  }
}
