import { Controller } from "@hotwired/stimulus"
// import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["assignSupervisorModal", "chosenSupervisor"]
  
  setSupervisor(event) {
    event.preventDefault();
    const deoId = event.currentTarget.dataset.deoId;
    this.assignSupervisorModalTarget.dataset.deoId = deoId;

    fetch('/managers/fetch_supervisors', {
      method: 'GET',
      headers: {
          Accept: 'application/json',
      },
    })
    .then(res => res.json())
    .then(data => {  
      const html = data.html;
      this.assignSupervisorModalTarget.innerHTML = html;
      this.assignSupervisorModalTarget.classList.remove("hidden")
    })
    .catch(error => {
        console.error("error", error);
    });

  }

  allocate(event) {
    event.preventDefault();

    const deoId = this.assignSupervisorModalTarget.dataset.deoId;
    const supervisorIds = this.chosenSupervisorTarget.value;
    const apiUrl = `/managers/data_entry_operators/${deoId}/assign_supervisor`;

    // Get current page from URL or store it somewhere (or pass it explicitly)
    const urlParams = new URLSearchParams(window.location.search);
    const currentPage = urlParams.get('page') || 1;
    console.log('urlParams', urlParams, "-- currentPage--- ", currentPage)

    fetch(apiUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "text/html", // Expect HTML
        "X-CSRF-Token": document.querySelector("meta[name='csrf-token']").content
      },
      body: JSON.stringify({ supervisorIds: [supervisorIds], page: currentPage })
    })
    .then(response => {
      if (response.redirected) {
        this.hideModal(); // Optionally hide modal first
        window.location.href = response.url; // Let browser fully navigate
      } else {
        throw new Error("Expected redirect response");
      }
    })
    .catch(error => {
      console.error("Error:", error);
    });
  }

  hideModal() {
    this.assignSupervisorModalTarget.classList.add("hidden");
  }
}
