import { Controller } from "@hotwired/stimulus"

export default class extends Controller {
  static targets = ["modal", "editModal"]

  connect() {}

  openModal() {
    this.modalTarget.classList.remove("hidden")
    this.modalTarget.classList.add("flex")
    document.body.classList.add("overflow-hidden")
  }

  openEditModal() {
    const dataValue = event.currentTarget.dataset.value;
    const parsedData = JSON.parse(dataValue);
    const editpath = parsedData.path;

    fetch(editpath, {
      method: 'GET',
      headers: {
          Accept: 'application/json',
      },
    })
    .then(res => res.json())
    .then(data => {  
      const html = data.html;
      this.editModalTarget.innerHTML = html;
      this.editModalTarget.classList.remove("hidden")
      this.editModalTarget.classList.add("flex")
      document.body.classList.add("overflow-hidden")
    })
    .catch(error => {
        console.error("error", error);
    });
  }

  closeModal() {
    this.modalTarget.classList.add("hidden")
    this.modalTarget.classList.remove("flex")
    document.body.classList.remove("overflow-hidden")
  }

  editCloseModal(){
    this.editModalTarget.classList.add("hidden")
    this.editModalTarget.classList.remove("flex")
    document.body.classList.remove("overflow-hidden")
  }
}
