import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = [
    "assignUsersModal",
    "assignUsersModalChosenManager",
    "assignUsersModalChosenSupervisor",
    "assignUsersModalChosenDataEntryOperator",
    "assignButton"
  ]

  setClient(event) {
    event.preventDefault();
    const clientId = event.currentTarget.dataset.clientId;
    this.currentclientId = clientId;
    
    // Get existing assignments if any
    const managerId = event.currentTarget.dataset.managerId;
    const supervisorId = event.currentTarget.dataset.supervisorId;
    const dataEntryOperatorId = event.currentTarget.dataset.dataEntryOperatorId;
    
    this.showModal();
    
    if (managerId) {
      this.assignUsersModalChosenManagerTarget.value = managerId;
      this.managerChanged();
      
      if (supervisorId) {
        setTimeout(() => {
          this.assignUsersModalChosenSupervisorTarget.value = supervisorId;
          this.supervisorChanged();
          
          if (dataEntryOperatorId) {
            setTimeout(() => {
              this.assignUsersModalChosenDataEntryOperatorTarget.value = dataEntryOperatorId;
              this.updateAssignButtonState();
            }, 300);
          }
        }, 300);
      }
    }
    
    // Initialize button state
    this.updateAssignButtonState();
  }

  allocate(event) {
    if (this.assignButtonTarget.disabled) return;
    event.preventDefault()
    const clientId = this.currentclientId;
    const managerIds = this.assignUsersModalChosenManagerTarget.value ? [this.assignUsersModalChosenManagerTarget.value] : []
    const supervisorIds = this.assignUsersModalChosenSupervisorTarget.value ? [this.assignUsersModalChosenSupervisorTarget.value] : []
    const dataEntryOperatorIds = this.assignUsersModalChosenDataEntryOperatorTarget.value ? [this.assignUsersModalChosenDataEntryOperatorTarget.value] : []
    const apiUrl = `/admin/clients/${clientId}/assign_users`

    const urlParams = new URLSearchParams(window.location.search);
    const currentPage = urlParams.get('page') || 1;

    fetch(apiUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "text/vnd.turbo-stream.html",
        "X-CSRF-Token": document.querySelector("meta[name='csrf-token']").content
      },
      body: JSON.stringify({
        manager_ids: managerIds,
        supervisor_ids: supervisorIds,
        data_entry_operator_ids: dataEntryOperatorIds,
        page: currentPage
      })
    })
    .then(async response => {
      if (response.ok) {
        const turboStream = await response.text();
        Turbo.renderStreamMessage(turboStream);
        this.hideModal();
      } else {
        console.error("Turbo Stream request failed:", response.statusText);
      }
    })
    .catch(error => {
      console.error("Error:", error);
    });
  }

  connect() {
    this.assignUsersModalChosenManagerTarget.addEventListener("change", this.managerChanged.bind(this))
    this.assignUsersModalChosenSupervisorTarget.addEventListener("change", this.supervisorChanged.bind(this))
    this.assignUsersModalChosenDataEntryOperatorTarget.addEventListener("change", this.updateAssignButtonState.bind(this))
  }

  managerChanged(event) {
    if (event && typeof event.preventDefault === 'function') {
      event.preventDefault()
    }
    
    const clientId = this.currentclientId;
    const managerId = event ? event.target.value : this.assignUsersModalChosenManagerTarget.value;
    const supervisorSelect = this.assignUsersModalChosenSupervisorTarget
    const dataEntryOperatorSelect = this.assignUsersModalChosenDataEntryOperatorTarget
    
    // Reset both dependent fields
    supervisorSelect.innerHTML = ""
    supervisorSelect.disabled = true
    supervisorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400')
    supervisorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white')
    
    dataEntryOperatorSelect.innerHTML = ""
    const defaultOperatorOption = document.createElement("option")
    defaultOperatorOption.value = ""
    defaultOperatorOption.text = "Select Data Entry Operator (choose supervisor first)"
    dataEntryOperatorSelect.appendChild(defaultOperatorOption)
    dataEntryOperatorSelect.disabled = true
    dataEntryOperatorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400')
    dataEntryOperatorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white')

    if (!managerId) {
      const defaultOption = document.createElement("option")
      defaultOption.value = ""
      defaultOption.text = "Select Supervisor (choose manager first)"
      supervisorSelect.appendChild(defaultOption)
      this.updateAssignButtonState()
      return
    }

    fetch(`/admin/clients/${clientId}/manager_supervisors?manager_id=${managerId}`, {
      headers: {
        "Accept": "application/json"
      }
    })
      .then(response => response.json())
      .then(data => {
        supervisorSelect.innerHTML = ""

        if (data.length > 0) {
          const defaultOption = document.createElement("option")
          defaultOption.value = ""
          defaultOption.text = "Select Supervisor"
          supervisorSelect.appendChild(defaultOption)
        }

        data.forEach(supervisor => {
          const option = document.createElement("option")
          option.value = supervisor.id
          option.text = supervisor.name
          supervisorSelect.appendChild(option)
        })

        if (data.length > 0) {
          supervisorSelect.disabled = false
          supervisorSelect.classList.remove('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400')
          supervisorSelect.classList.add('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white')
        } else {
          const noSupervisorsOption = document.createElement("option")
          noSupervisorsOption.value = ""
          noSupervisorsOption.text = "No supervisors available"
          supervisorSelect.appendChild(noSupervisorsOption)
        }
        this.updateAssignButtonState()
      })
      .catch(error => {
        console.error("Error fetching supervisors:", error)
      })
  }

  supervisorChanged(event) {
    if (event && typeof event.preventDefault === 'function') {
      event.preventDefault()
    }
    
    const clientId = this.currentclientId;
    const supervisorId = event ? event.target.value : this.assignUsersModalChosenSupervisorTarget.value;
    const dataEntryOperatorSelect = this.assignUsersModalChosenDataEntryOperatorTarget
    
    dataEntryOperatorSelect.innerHTML = ""
    dataEntryOperatorSelect.disabled = true
    dataEntryOperatorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400')
    dataEntryOperatorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white')

    if (!supervisorId) {
      const defaultOption = document.createElement("option")
      defaultOption.value = ""
      defaultOption.text = "Select Data Entry Operator (choose supervisor first)"
      dataEntryOperatorSelect.appendChild(defaultOption)
      this.updateAssignButtonState()
      return
    }

    fetch(`/admin/clients/${clientId}/supervisor_data_entry_operators?supervisor_id=${supervisorId}`, {
      headers: {
        "Accept": "application/json"
      }
    })
      .then(response => response.json())
      .then(data => {
        dataEntryOperatorSelect.innerHTML = ""

        if (data.length > 0) {
          const defaultOption = document.createElement("option")
          defaultOption.value = ""
          defaultOption.text = "Select Data Entry Operator"
          dataEntryOperatorSelect.appendChild(defaultOption)
        }

        data.forEach(operator => {
          const option = document.createElement("option")
          option.value = operator.id
          option.text = operator.name
          dataEntryOperatorSelect.appendChild(option)
        })

        if (data.length > 0) {
          dataEntryOperatorSelect.disabled = false
          dataEntryOperatorSelect.classList.remove('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400')
          dataEntryOperatorSelect.classList.add('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white')
        } else {
          const noOperatorsOption = document.createElement("option")
          noOperatorsOption.value = ""
          noOperatorsOption.text = "No data entry operators available"
          dataEntryOperatorSelect.appendChild(noOperatorsOption)
        }
        this.updateAssignButtonState()
      })
      .catch(error => {
        console.error("Error fetching data entry operators:", error)
      })
  }

  updateAssignButtonState() {
    const managerSelected = this.assignUsersModalChosenManagerTarget.value !== "";
    const supervisorSelected = this.assignUsersModalChosenSupervisorTarget.value !== "";
    const dataEntryOperatorSelected = this.assignUsersModalChosenDataEntryOperatorTarget.value !== "";
    
    const hasSupervisors = this.assignUsersModalChosenSupervisorTarget.querySelectorAll('option').length > 1;
    const hasDataEntryOperators = this.assignUsersModalChosenDataEntryOperatorTarget.querySelectorAll('option').length > 1;
    
    // Enable only if:
    // 1. Manager is selected and no supervisors available, or
    // 2. Manager and supervisor selected and no data entry operators available, or
    // 3. All three are selected
    const shouldEnable = (managerSelected && !hasSupervisors) ||
                        (managerSelected && supervisorSelected && !hasDataEntryOperators) ||
                        (managerSelected && supervisorSelected && dataEntryOperatorSelected);
    
    this.assignButtonTarget.disabled = !shouldEnable;
    
    if (shouldEnable) {
      this.assignButtonTarget.classList.remove('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
      this.assignButtonTarget.classList.add('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
    } else {
      this.assignButtonTarget.classList.remove('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
      this.assignButtonTarget.classList.add('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
    }
  }

  showModal() {
    this.assignUsersModalTarget.classList.remove("hidden");
    document.body.classList.add("overflow-hidden");
    this.updateAssignButtonState();
  }

  hideModal() {
    this.assignUsersModalTarget.classList.add("hidden");
    document.body.classList.remove("overflow-hidden");
    this.assignUsersModalChosenManagerTarget.value = "";
    
    // Reset supervisor dropdown
    const supervisorSelect = this.assignUsersModalChosenSupervisorTarget;
    supervisorSelect.innerHTML = "";
    const defaultSupervisorOption = document.createElement("option");
    defaultSupervisorOption.value = "";
    defaultSupervisorOption.text = "Select Supervisor (choose manager first)";
    supervisorSelect.appendChild(defaultSupervisorOption);
    supervisorSelect.disabled = true;
    supervisorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400');
    supervisorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white');
    
    // Reset data entry operator dropdown
    const dataEntryOperatorSelect = this.assignUsersModalChosenDataEntryOperatorTarget;
    dataEntryOperatorSelect.innerHTML = "";
    const defaultOperatorOption = document.createElement("option");
    defaultOperatorOption.value = "";
    defaultOperatorOption.text = "Select Data Entry Operator (choose supervisor first)";
    dataEntryOperatorSelect.appendChild(defaultOperatorOption);
    dataEntryOperatorSelect.disabled = true;
    dataEntryOperatorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400');
    dataEntryOperatorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white');
    
    this.updateAssignButtonState();
  }
}
