import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = [
    "modal",
    "statusField",
    "rejectionReasonField",
    "descriptionField",
    "commentTypeField",
    "form",
    "submitButton",
    "rejectionReasonContainer",
    "descriptionContainer",
    "statusError",
    "rejectionReasonError",
    "descriptionError",
    "formError", 
    "previousCommentsSection"
  ]
  static values = { 
    url: String,
    currentPage: Number 
  }

  connect() {
    this.currentId = null
    this.setupStatusChangeListener()
  }

  verify(event) {
    event.preventDefault()

    const modal = document.getElementById('document-verification-modal')
    this.currentId = event.currentTarget.dataset.documentId

    // Read data from button
    const currentStatus = event.currentTarget.dataset.documentStatus
    const currentRejectionReason = event.currentTarget.dataset.documentRejectionReason
    const currentQueryDescription = event.currentTarget.dataset.queryDescription
    const currentCommentDescription = event.currentTarget.dataset.commentDescription

    const commentsJSON = event.currentTarget.dataset.documentComments
    const comments = commentsJSON ? JSON.parse(commentsJSON) : []

    // Set form fields
    const validStatuses = Array.from(this.statusFieldTarget.options).map(option => option.value)
    if (currentStatus && validStatuses.includes(currentStatus)) {
      this.statusFieldTarget.value = currentStatus
    } else {
      this.statusFieldTarget.selectedIndex = 0
    }

    this.rejectionReasonFieldTarget.value = currentRejectionReason || ''
    
    // Set description field based on current status
    if (currentStatus === 'query_raised') {
      this.descriptionFieldTarget.value = currentQueryDescription || ''
    } else if (currentStatus === 'query_resolved') {
      this.descriptionFieldTarget.value = currentCommentDescription || ''
    } else {
      this.descriptionFieldTarget.value = ''
    }

    // Update previous comments list inside modal
    this.updatePreviousComments(comments)
    // Show modal
    this.toggleConditionalFields()
    modal.classList.remove('hidden')
    this.clearErrors()
  }

  updatePreviousComments(comments) {
    if (comments.length === 0) {
      this.previousCommentsSectionTarget.classList.add('hidden')
      this.previousCommentsSectionTarget.innerHTML = ''
      return
    }

    this.previousCommentsSectionTarget.innerHTML = `
      <p class="text-lg font-semibold mb-4 text-neutral-900 dark:text-white">Previous Comments</p>
      <ul class="max-h-48 overflow-y-auto space-y-2 pr-2 scrollbar-thin scrollbar-thumb-rounded scrollbar-thumb-gray-400 dark:scrollbar-thumb-gray-700">
        ${comments.map(comment => `
          <li class="p-2 border border-neutral-300 dark:border-neutral-700 rounded-md bg-gray-50 dark:bg-gray-800 text-xs shadow-sm">
            <div class="flex items-center justify-between mb-1">
              <span class="px-1.5 py-0.25 font-semibold rounded ${
                comment.type === 'query' 
                  ? 'bg-yellow-200 text-yellow-800 dark:bg-yellow-600 dark:text-yellow-100' 
                  : 'bg-green-200 text-green-800 dark:bg-green-600 dark:text-green-100'
              }">
                ${comment.type === 'query' ? 'Query' : 'Comment'}
              </span>
              <time class="text-gray-500 dark:text-gray-400">${comment.created_at}</time>
            </div>
            <p class="pl-4 text-neutral-700 dark:text-gray-300 truncate" title="${comment.description}">
              ${comment.description.length > 60 ? comment.description.substring(0, 60) + '...' : comment.description}
            </p>
          </li>
        `).join('')}
      </ul>
    `

    this.previousCommentsSectionTarget.classList.remove('hidden')
  }

  cancelVerification() {
    this.modalTarget.classList.add("hidden")
    this.currentId = null
    this.formTarget.reset()
    this.toggleConditionalFields()
    this.clearErrors()
  }

  setupStatusChangeListener() {
    this.statusFieldTarget.addEventListener('change', () => {
      this.toggleConditionalFields()
      this.clearErrors()
    })
  }

  toggleConditionalFields() {
    const status = this.statusFieldTarget.value
    
    // Handle rejection reason field
    if (status === 'rejected') {
      this.rejectionReasonContainerTarget.classList.remove('hidden')
      this.descriptionContainerTarget.classList.add('hidden')
      this.commentTypeFieldTarget.value = ''
    } else {
      this.rejectionReasonContainerTarget.classList.add('hidden')
      this.rejectionReasonFieldTarget.value = ''
    }
    
    // Handle description field and comment type
    if (status === 'query_raised') {
      this.descriptionContainerTarget.classList.remove('hidden')
      this.commentTypeFieldTarget.value = 'query'
    } else if (status === 'query_resolved') {
      this.descriptionContainerTarget.classList.remove('hidden')
      this.commentTypeFieldTarget.value = 'comment'
    } else {
      this.descriptionContainerTarget.classList.add('hidden')
      this.commentTypeFieldTarget.value = ''
    }
    
    // Handle comments section visibility
    if (this.hasPreviousCommentsSectionTarget) {
      const showStatuses = ['query_raised', 'query_resolved']
      if (showStatuses.includes(status)) {
        this.previousCommentsSectionTarget.classList.remove('hidden')
      } else {
        this.previousCommentsSectionTarget.classList.add('hidden')
      }
    }
  }

  clearErrors() {
    this.statusErrorTarget.classList.add('hidden')
    this.rejectionReasonErrorTarget.classList.add('hidden')
    this.descriptionErrorTarget.classList.add('hidden')
    this.formErrorTarget.classList.add('hidden')
  }

  showError(target, message) {
    target.textContent = message
    target.classList.remove('hidden')
  }

  async submitVerification(event) {
    event.preventDefault();
    this.clearErrors();

    if (!this.currentId) {
      this.showError(this.formErrorTarget, 'No document selected');
      return;
    }

    const status = this.statusFieldTarget.value;
    const rejectionReason = this.rejectionReasonFieldTarget.value.trim();
    const description = this.descriptionFieldTarget.value.trim();

    if (status === 'rejected' && !rejectionReason) {
      this.showError(this.rejectionReasonErrorTarget, 'Reason is required when rejecting a document');
      return;
    }

    if ((status === 'query_raised' || status === 'query_resolved') && !description) {
      this.showError(this.descriptionErrorTarget, 'Description is required');
      return;
    }

    const submitButton = this.submitButtonTarget;
    submitButton.disabled = true;
    submitButton.classList.add('opacity-50', 'cursor-not-allowed');

    const urlWithPage = `${this.urlValue}/${this.currentId}/verify?page=${this.currentPageValue}`;

    try {
      const response = await fetch(urlWithPage, {
        method: 'PATCH',
        headers: {
          'X-CSRF-Token': document.querySelector("[name='csrf-token']").content,
          'Content-Type': 'application/json',
          'Accept': 'text/vnd.turbo-stream.html, application/json',
        },
        body: JSON.stringify({
          document: {
            status: status,
            rejection_reason: status === 'rejected' ? rejectionReason : null,
          },
          document_comment_description: description,
          comment_type: this.commentTypeFieldTarget.value,
        }),
      });

      const contentType = response.headers.get("content-type");

      if (response.ok) {
        if (contentType && contentType.includes("text/vnd.turbo-stream.html")) {
          const turboStream = await response.text();
          Turbo.renderStreamMessage(turboStream);
          this.cancelVerification();
        } else if (contentType && contentType.includes("application/json")) {
          const data = await response.json();
          if (data.status === 'success') {
            window.location.reload();
          } else {
            this.showError(this.formErrorTarget, data.error || 'Failed to verify document');
          }
        }
      } else {
        const data = await response.json();
        if (data.errors) {
          if (data.errors.status) {
            this.showError(this.statusErrorTarget, data.errors.status.join(', '));
          }
          if (data.errors.rejection_reason) {
            this.showError(this.rejectionReasonErrorTarget, data.errors.rejection_reason.join(', '));
          }
          if (data.errors.document_comment_description) {
            this.showError(this.descriptionErrorTarget, data.errors.document_comment_description.join(', '));
          }
          if (data.errors.base) {
            this.showError(this.formErrorTarget, data.errors.base.join(', '));
          }
        } else {
          this.showError(this.formErrorTarget, data.error || 'Failed to verify document');
        }
      }
    } catch (error) {
      console.error('Verification error:', error);
      this.showError(this.formErrorTarget, 'Network error - please try again');
    } finally {
      submitButton.disabled = false;
      submitButton.classList.remove('opacity-50', 'cursor-not-allowed');
    }
  }
}
