import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = [
    "assignUsersModal",
    "assignUsersModalChosenManager",
    "assignUsersModalChosenSupervisor",
    "assignButton"
  ]

  setDataEntryOperator(event) {
    event.preventDefault();
    const dataEntryOperatorId = event.currentTarget.dataset.dataEntryOperatorId;
    this.currentDataEntryOperatorId = dataEntryOperatorId;
    
    // Get existing assignments if any
    const managerId = event.currentTarget.dataset.managerId;
    const supervisorId = event.currentTarget.dataset.supervisorId;
    
    this.showModal();
    
    if (managerId) {
      this.assignUsersModalChosenManagerTarget.value = managerId;
      this.managerChanged();
      
      if (supervisorId) {
        // Give time for supervisor options to load
        setTimeout(() => {
          this.assignUsersModalChosenSupervisorTarget.value = supervisorId;
          this.updateAssignButtonState();
        }, 300);
      }
    }
    
    // Initialize button state
    this.updateAssignButtonState();
  }

  allocate(event) {
    if (this.assignButtonTarget.disabled) return;
    event.preventDefault();
    
    const dataEntryOperatorId = this.currentDataEntryOperatorId;
    const managerIds = this.assignUsersModalChosenManagerTarget.value ? [this.assignUsersModalChosenManagerTarget.value] : [];
    const supervisorIds = this.assignUsersModalChosenSupervisorTarget.value ? [this.assignUsersModalChosenSupervisorTarget.value] : [];
    const apiUrl = `/admin/data_entry_operators/${dataEntryOperatorId}/assign_users`;

    const urlParams = new URLSearchParams(window.location.search);
    const currentPage = urlParams.get('page') || 1;

    fetch(apiUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "text/vnd.turbo-stream.html",
        "X-CSRF-Token": document.querySelector("meta[name='csrf-token']").content
      },
      body: JSON.stringify({
        manager_ids: managerIds,
        supervisor_ids: supervisorIds,
        page: currentPage
      })
    })
    .then(async response => {
      if (response.ok) {
        const turboStream = await response.text();
        Turbo.renderStreamMessage(turboStream);
        this.hideModal();
      } else {
        console.error("Turbo Stream request failed:", response.statusText);
      }
    })
    .catch(error => {
      console.error("Error:", error);
    });
  }

  connect() {
    this.assignUsersModalChosenManagerTarget.addEventListener("change", this.managerChanged.bind(this));
    this.assignUsersModalChosenSupervisorTarget.addEventListener("change", this.updateAssignButtonState.bind(this));
  }

  managerChanged(event) {
    if (event && typeof event.preventDefault === 'function') {
      event.preventDefault();
    }
    
    const dataEntryOperatorId = this.currentDataEntryOperatorId;
    const managerId = event ? event.target.value : this.assignUsersModalChosenManagerTarget.value;
    const supervisorSelect = this.assignUsersModalChosenSupervisorTarget;
    
    // Reset supervisor field
    supervisorSelect.innerHTML = "";
    supervisorSelect.disabled = true;
    supervisorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400');
    supervisorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white');

    if (!managerId) {
      const defaultOption = document.createElement("option");
      defaultOption.value = "";
      defaultOption.text = "Select Supervisor (choose manager first)";
      supervisorSelect.appendChild(defaultOption);
      this.updateAssignButtonState();
      return;
    }

    fetch(`/admin/data_entry_operators/${dataEntryOperatorId}/manager_supervisors?manager_id=${managerId}`, {
      headers: {
        "Accept": "application/json"
      }
    })
    .then(response => response.json())
    .then(data => {
      supervisorSelect.innerHTML = "";

      // Always add default option
      const defaultOption = document.createElement("option");
      defaultOption.value = "";
      defaultOption.text = data.length > 0 ? "Select Supervisor" : "No supervisors available";
      supervisorSelect.appendChild(defaultOption);

      // Add supervisor options if available
      data.forEach(supervisor => {
        const option = document.createElement("option");
        option.value = supervisor.id;
        option.text = supervisor.name;
        supervisorSelect.appendChild(option);
      });

      if (data.length > 0) {
        supervisorSelect.disabled = false;
        supervisorSelect.classList.remove('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400');
        supervisorSelect.classList.add('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white');
      }
      
      this.updateAssignButtonState();
    })
    .catch(error => {
      console.error("Error fetching supervisors:", error);
      // Add error option
      const errorOption = document.createElement("option");
      errorOption.value = "";
      errorOption.text = "Error loading supervisors";
      supervisorSelect.appendChild(errorOption);
      this.updateAssignButtonState();
    });
  }

  updateAssignButtonState() {
    const managerSelected = this.assignUsersModalChosenManagerTarget.value !== "";
    const supervisorSelected = this.assignUsersModalChosenSupervisorTarget.value !== "";
    const hasSupervisors = this.assignUsersModalChosenSupervisorTarget.querySelectorAll('option').length > 1; // More than just the default
    
    // Enable button if:
    // 1. Manager is selected and no supervisors available, OR
    // 2. Both manager and supervisor are selected
    const shouldEnable = (managerSelected && !hasSupervisors) || 
                        (managerSelected && supervisorSelected);
    
    this.assignButtonTarget.disabled = !shouldEnable;
    
    if (shouldEnable) {
      this.assignButtonTarget.classList.remove('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
      this.assignButtonTarget.classList.add('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
    } else {
      this.assignButtonTarget.classList.remove('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
      this.assignButtonTarget.classList.add('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
    }
  }

  showModal() {
    this.assignUsersModalTarget.classList.remove("hidden");
    document.body.classList.add("overflow-hidden");
    this.updateAssignButtonState();
  }

  hideModal() {
    this.assignUsersModalTarget.classList.add("hidden");
    document.body.classList.remove("overflow-hidden");
    this.assignUsersModalChosenManagerTarget.value = "";
    
    // Reset supervisor dropdown
    const supervisorSelect = this.assignUsersModalChosenSupervisorTarget;
    supervisorSelect.innerHTML = "";
    const defaultOption = document.createElement("option");
    defaultOption.value = "";
    defaultOption.text = "Select Supervisor (choose manager first)";
    supervisorSelect.appendChild(defaultOption);
    supervisorSelect.disabled = true;
    supervisorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400');
    supervisorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white');
    
    this.updateAssignButtonState();
  }
}
