import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = [
    "modal", "form",
    "nameField", "emailField",
    "mobileField", "whatsappField", 
    "panField", "gstField", 
    "businessTypeField", "addressField", 
    "nameError",
    "mobileError", "whatsappError", 
    "panError", "gstError", 
    "businessTypeError", "addressError"
  ]
  static values = { 
    editUrl: String,
    resource: String
  }

  connect() {
    this.currentId = null
  }

  edit(event) {
    event.preventDefault()
    const row = event.target.closest("tr")
    this.currentId = row.dataset.clientId

    if (!this.currentId) {
      console.error("No ID found for resource")
      return
    }

    fetch(`${this.editUrlValue}/${this.currentId}/edit`, {
      headers: { 'Accept': 'application/json' }
    })
      .then(response => response.json())
      .then(data => {
        if (this.hasNameFieldTarget) this.nameFieldTarget.value = data.name || ''
        if (this.hasEmailFieldTarget) this.emailFieldTarget.value = data.email || ''

        if (data.profile) {
          if (this.hasMobileFieldTarget) this.mobileFieldTarget.value = data.profile.mobile_no || ''
          if (this.hasWhatsappFieldTarget) this.whatsappFieldTarget.value = data.profile.whatsapp_no || ''
          if (this.hasPanFieldTarget) this.panFieldTarget.value = data.profile.pan_no || ''
          if (this.hasGstFieldTarget) this.gstFieldTarget.value = data.profile.gst_no || ''
          if (this.hasBusinessTypeFieldTarget) {
            this.businessTypeFieldTarget.value = data.profile.business_type || ''
          }
          if (this.hasAddressFieldTarget) this.addressFieldTarget.value = data.profile.address || ''
        }

        this.clearErrors()
        this.modalTarget.classList.remove("hidden")
      })
      .catch(error => {
        console.error("Error:", error)
        this.showError('name', 'Failed to load details')
      })
  }

  async submit(event) {
    event.preventDefault();

    if (!this.currentId) {
      this.showError('name', 'No client selected');
      return;
    }

    const urlParams = new URLSearchParams(window.location.search);
    const currentPage = urlParams.get('page') || 1;

    const body = {
      client: {
        name: this.nameFieldTarget?.value || '',
        profile_attributes: {
          mobile_no: this.mobileFieldTarget?.value || '',
          whatsapp_no: this.whatsappFieldTarget?.value || '',
          pan_no: this.panFieldTarget?.value || '',
          gst_no: this.gstFieldTarget?.value || '',
          business_type: this.businessTypeFieldTarget?.value || '',
          address: this.addressFieldTarget?.value || ''
        }
      }
    };

    // Clean empty values to avoid validation issues
    Object.keys(body.client.profile_attributes).forEach(key => {
      if (body.client.profile_attributes[key] === '') {
        delete body.client.profile_attributes[key];
      }
    });

    this.clearErrors();

    fetch(`${this.editUrlValue}/${this.currentId}?page=${currentPage}`, {
      method: 'PATCH',
      headers: {
        'X-CSRF-Token': document.querySelector("[name='csrf-token']").content,
        'Content-Type': 'application/json',
        'Accept': 'text/vnd.turbo-stream.html, application/json'
      },
      body: JSON.stringify(body)
    })
    .then(response => {
      const contentType = response.headers.get('content-type') || '';

      if (response.ok && contentType.includes('text/vnd.turbo-stream.html')) {
        return response.text().then(html => ({ type: 'turbo', html }));
      }

      if (!response.ok && contentType.includes('application/json')) {
        return response.json().then(data => ({ type: 'json', data }));
      }

      throw new Error('Unexpected response format');
    })
    .then(result => {
      if (result.type === 'turbo') {
        Turbo.renderStreamMessage(result.html);
        setTimeout(() => document.querySelector('.flash, .alert, .notice')?.remove(), 3000);
        this.cancel();
      } else if (result.type === 'json') {
        this.handleErrors(result.data.errors);
      }
    })
    .catch(error => {
      console.error('Error:', error);
      this.clearErrors();
      this.showError('name', 'Something went wrong. Please try again.');
    });
  }

  handleErrors(errors) {
    if (!errors) return;

    const uniqueMessages = (messages) => {
      if (!Array.isArray(messages)) return messages;
      return [...new Set(messages)]; // Remove duplicates
    };

    if (errors.profile) {
      Object.entries(errors.profile).forEach(([field, messages]) => {
        const targetField = field.replace('_no', '');
        this.showError(targetField, uniqueMessages(messages).join(', '));
      });
    }

    if (errors.client) {
      Object.entries(errors.client).forEach(([field, messages]) => {
        this.showError(field, uniqueMessages(messages).join(', '));
      });
    }

    if (errors.base) {
      this.showError('name', uniqueMessages(errors.base).join(', '));
    }
  }

  cancel() {
    this.modalTarget.classList.add("hidden")
    this.currentId = null
    this.formTarget.reset()
    this.clearErrors()
  }

  clearErrors() {
    this.errorTargets.forEach(target => {
      if (this[`${target}Target`]) {
        this[`${target}Target`].textContent = ''
        this[`${target}Target`].classList.add('hidden')
      }
    })
  }

  showError(field, message) {
    const errorTarget = `${field}ErrorTarget`
    if (this[errorTarget]) {
      this[errorTarget].textContent = message
      this[errorTarget].classList.remove('hidden')
    }
  }

  get errorTargets() {
    return [
      'nameError', 'mobileError', "whatsappError",
      'panError', 'gstError', 'businessTypeError', 
      'addressError'
    ]
  }
}
