import { Controller } from "@hotwired/stimulus"
import { renderStreamMessage } from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["modal", "companyIdInput", "companyIdError"]

  connect() {}

  showModal(event) {
    this.currentClientId = event.currentTarget.dataset.clientId;
    const currentCompanyId = event.currentTarget.dataset.companyId || "";
    this.companyIdInputTarget.value = currentCompanyId;
    this.clearError();
    this.modalTarget.classList.remove("hidden");
  }

  saveCompanyId(event) {
    event.preventDefault();
    const companyId = this.companyIdInputTarget.value.trim();

    if (!companyId) {
      this.showError("Company ID can’t be blank");
      return;
    }

    fetch(`/managers/clients/${this.currentClientId}/set_company_id`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "text/vnd.turbo-stream.html",
        "X-CSRF-Token": document.querySelector("meta[name='csrf-token']").content
      },
      body: JSON.stringify({ company_id: companyId })
    })
      .then(response => {
        if (!response.ok) {
          return response.text().then(html => {
            this.modalTarget.innerHTML = html;
            throw new Error("Validation failed");
          });
        }
        return response.text();
      })
      .then(html => {
        renderStreamMessage(html);
        this.clearError();
        this.hideModal();
      })
      .catch(error => {
        console.error("Error:", error);
      });
  }

  showError(message) {
    this.companyIdErrorTarget.textContent = message;
    this.companyIdErrorTarget.classList.remove("hidden");
  }

  clearError() {
    this.companyIdErrorTarget.textContent = "";
    this.companyIdErrorTarget.classList.add("hidden");
  }

  hideModal() {
    this.modalTarget.classList.add("hidden");
  }
}
