import { Controller } from "@hotwired/stimulus"

export default class extends Controller {
  static targets = ["start", "end"]

  connect() {
    // Create Flatpickr instance for start date and store it
    this.startPicker = window.flatpickr(this.startTarget, {
      dateFormat: "Y-m-d",
      clickOpens: false, // We'll handle opening manually
      disableMobile: true, // <--- Add this line
      onChange: (selectedDates) => {
        if (selectedDates.length && this.hasEndTarget) {
          this.endPicker.set("minDate", selectedDates[0])
        }
      }
    });

    // Create Flatpickr instance for end date and store it
    this.endPicker = window.flatpickr(this.endTarget, {
      dateFormat: "Y-m-d",
      clickOpens: false, // We'll handle opening manually
      disableMobile: true // <--- Add this line
    });

    // Add event listeners for manual toggle
    this.startTarget.addEventListener("click", () => this.toggleCalendar(this.startPicker));
    this.endTarget.addEventListener("click", () => this.toggleCalendar(this.endPicker));
  }

  toggleCalendar(pickerInstance) {
    if (pickerInstance.isOpen) {
      pickerInstance.close();
    } else {
      pickerInstance.open();
    }
  }
}
