import { Controller } from "@hotwired/stimulus"

export default class extends Controller {
  static targets = [
    "modal", "createModal",
    "nameField", "emailField",
    "nameError", "emailError"
  ]

  connect() {
    this.close()
  }

  open() {
    this.modalTarget.classList.remove("hidden")
    document.body.classList.add("overflow-hidden")
  }

  close() {
    // this.createModalTarget.classList.add("hidden")
    this.modalTarget.classList.add("hidden")
    document.body.classList.remove("overflow-hidden")
  }

  handleKeydown(event) {
    if (event.key === "Escape") {
      this.close()
    }
  }

  closeBackground(event) {
    if (event.target === this.createModalTarget) {
      this.close()
    }
  }

  handleSubmitEnd(event) {
    if (event.detail.success) {
      this.close()
    }
    // If not successful, the modal will stay open with error messages
  }

  async submit(event) {
    event.preventDefault()

    const body = {
      client: {
        name: this.nameFieldTarget?.value || '',
        email: this.emailFieldTarget?.value || '',
        profile_attributes: {
          mobile_no: this.mobileFieldTarget?.value || '',
          pan_no: this.panFieldTarget?.value || '',
          gst_no: this.gstFieldTarget?.value || '',
          business_type: this.businessTypeFieldTarget?.value || '',
          address: this.addressFieldTarget?.value || '',
          whatsapp_no: this.whatsappFieldTarget?.value || '',
        }
      }
    }

    const response = await fetch('/admin/clients', {
      method: 'POST',
      headers: {
        'X-CSRF-Token': document.querySelector("[name='csrf-token']").content,
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: JSON.stringify(body)
    })

    const data = await response.json()

    if (!response.ok) {
      this.clearErrors()
      this.handleErrors(data.errors)
      return
    }
    this.close()
    window.location.reload()
  }

  handleErrors(errors) {
    if (!errors) return;

    const uniqueMessages = (messages) => {
      if (!Array.isArray(messages)) return messages;
      return [...new Set(messages)]; // Remove duplicates
    };

    if (errors.client) {
      Object.entries(errors.client).forEach(([field, messages]) => {
        this.showError(field, uniqueMessages(messages).join(', '));
      });
    }
  }

  clearErrors() {
    this.errorTargets.forEach(target => {
      if (this[`${target}Target`]) {
        this[`${target}Target`].textContent = ''
        this[`${target}Target`].classList.add('hidden')
      }
    })
  }

  showError(field, message) {
    console.log('showError', field, 'message:', message)
    const errorTarget = `${field}ErrorTarget`
    if (this[errorTarget]) {
      this[errorTarget].textContent = this.capitalizeFirstLetter(field) + " " + message
      this[errorTarget].classList.remove('hidden')
    }
  }

  get errorTargets() {
    return [
      'nameError', 'emailError', 'mobileError',
      'panError', 'gstError', 'businessTypeError',
      'addressError', 
    ]
  }

  capitalizeFirstLetter(string) {
    return string.charAt(0).toUpperCase() + string.slice(1);
  }
}