import { Controller } from "@hotwired/stimulus"
import chatChannel  from "../../channels/chat_channel"

export default class extends Controller {
  static targets = ["input", "submitButton", "fileInput", "filePreviewContainer", "filePreviews"]

  connect() {
    this.scrollToBottom()
    this.userScrolledUp = false
    this.setupScrollTracking()

    const recipientId = document.getElementById('recipient_id')?.value
    if (recipientId) {
      chatChannel(recipientId)
    }

    document.addEventListener('turbo:frame-load', this.handleTurboFrameLoad.bind(this))
    document.addEventListener('turbo:before-stream-render', this.handleTurboStreamRender.bind(this))
  }

  setupScrollTracking() {
    const container = document.getElementById('messages')
    if (!container) return

    container.addEventListener('scroll', () => {
      const { scrollTop, scrollHeight, clientHeight } = container
      this.userScrolledUp = scrollTop + clientHeight < scrollHeight - 100
    })
  }

  handleTurboFrameLoad(event) {
    if (event.target.id === 'client_message_blocks') {
      this.scrollToBottomIfNotScrolledUp()
    }
  }

  handleTurboStreamRender(event) {
    event.detail.render(event)
    this.scrollToBottomIfNotScrolledUp()
  }

  scrollToBottomIfNotScrolledUp() {
    if (!this.userScrolledUp) {
      this.scrollToBottom()
    }
  }

  scrollToBottom() {
    const container = document.getElementById('messages')
    if (container) {
      requestAnimationFrame(() => {
        container.scrollTo({
          top: container.scrollHeight,
          behavior: 'auto'
        })
      })
    }
  }

  submitForm(event) {
    event.preventDefault()
    if (!this.hasContent()) return

    const formData = new FormData(this.element)
    this.clearForm()

    fetch(this.element.action, {
      method: this.element.method,
      body: formData,
      headers: {
        'Accept': 'text/vnd.turbo-stream.html',
        'X-CSRF-Token': document.querySelector('[name="csrf-token"]').content
      }
    })
    .then(response => response.ok ? this.scrollToBottom() : this.showError())
    .catch(() => this.showError())
  }

  toggleSubmitButton() {
    this.submitButtonTarget.style.display = this.hasContent() ? 'flex' : 'none'
  }

  triggerFileInput() {
    this.fileInputTarget.click()
  }

  displayFilePreview() {
    if (this.fileInputTarget.files.length === 0) return

    this.filePreviewsTarget.innerHTML = Array.from(this.fileInputTarget.files)
      .map(file => this.createFilePreview(file))
      .join('')

    this.filePreviewContainerTarget.classList.remove('hidden')
    this.toggleSubmitButton()
  }

  hasContent() {
    return this.inputTarget.value.trim() || this.fileInputTarget.files.length > 0
  }

  clearForm() {
    this.inputTarget.value = ''
    this.clearAllFiles()
  }

  createFilePreview(file) {
    return `
      <div class="flex items-center gap-2 bg-white dark:bg-neutral-600 rounded-lg p-2 flex-shrink-0">
        ${file.type.startsWith('image/') ?
        `<iconify-icon icon="heroicons:photo" class="text-4xl text-primary-600 dark:text-primary-400"></iconify-icon>` :
        `<iconify-icon icon="heroicons:document" class="text-lg"></iconify-icon>`}
        <span class="text-sm truncate max-w-[100px]">${file.name}</span>
        <button type="button" class="text-neutral-500 dark:text-neutral-300 hover:text-red-500"
                data-action="click->client--message#removeFile" data-filename="${file.name}">
          <iconify-icon icon="heroicons:x-mark" class="text-sm"></iconify-icon>
        </button>
      </div>`
  }

  removeFile(event) {
    const fileName = event.target.closest('button').dataset.filename
    const dataTransfer = new DataTransfer()

    Array.from(this.fileInputTarget.files)
      .filter(file => file.name !== fileName)
      .forEach(file => dataTransfer.items.add(file))

    this.fileInputTarget.files = dataTransfer.files
    event.target.closest('div').remove()
    this.toggleSubmitButton()

    if (this.filePreviewsTarget.children.length === 0) {
      this.filePreviewContainerTarget.classList.add('hidden')
    }
  }

  clearAllFiles() {
    this.fileInputTarget.value = ''
    this.filePreviewsTarget.innerHTML = ''
    this.filePreviewContainerTarget.classList.add('hidden')
  }

  showError() {
    const alert = document.createElement('div')
    document.body.appendChild(alert)
    setTimeout(() => alert.remove(), 3000)
  }
}
