import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["modal", "content", "form"]

  connect() {
    this.userId = null
    this.userType = null
  }

  open(event) {
    event.preventDefault()
    const button = event.currentTarget
    this.userId = button.dataset.userId
    this.userType = button.dataset.userType
    this.fetchGroups()
  }

  fetchGroups() {
    const path = `/admin/${this.userType}/${this.userId}/get_groups`
    fetch(path, {
      headers: { "Accept": "application/json" }
    })
      .then(res => res.json())
      .then(data => this.renderGroups(data))
      .catch(err => console.error("Error fetching groups:", err))
  }

  renderGroups(data) {
    const groupsHtml = data.groups.map(group => {
      const isChecked = data.assigned_group_ids.includes(group.id)
      return `
        <div class="flex items-center justify-between py-2 border-b border-gray-300 dark:border-gray-600">
          <!-- Checkbox -->
          <input type="checkbox"
                name="group_ids[]"
                value="${group.id}"
                ${isChecked ? "checked" : ""}
                class="h-5 w-5 border-gray-300 dark:border-gray-600 rounded mr-4">

          <!-- Group name and permissions count in one line -->
          <div class="flex items-center flex-grow space-x-2 text-lg text-gray-900 dark:text-gray-100">
            <span>${group.name}</span>
            <small class="text-base text-gray-600 dark:text-gray-400">
              (${group.permissions_count} permissions)
            </small>
          </div>
        </div>
      `
    }).join("")

    this.contentTarget.innerHTML = `
      <div class="max-h-[60vh] overflow-y-auto pr-2">
        ${groupsHtml}
      </div>
    `
    this.modalTarget.classList.remove("hidden")
  }

  save(event) {
    event.preventDefault()
    const formData = new FormData(this.formTarget)
    const urlParams = new URLSearchParams(window.location.search)
    const currentPage = urlParams.get('page') || 1
    const path = `/admin/${this.userType}/${this.userId}/assign_groups?page=${currentPage}`

    fetch(path, {
      method: "POST",
      body: formData,
      headers: {
        'X-Requested-With': 'XMLHttpRequest',
        'Accept': 'text/vnd.turbo-stream.html',
        'X-CSRF-Token': document.querySelector('meta[name="csrf-token"]').content
      }
    })
      .then(response => response.text())
      .then(html => {
        Turbo.renderStreamMessage(html)
        this.close()
      })
      .catch(err => console.error("Error saving permissions:", err))
  }

  close() {
    this.modalTarget.classList.add("hidden")
    this.contentTarget.innerHTML = ""
    this.userId = null
    this.userType = null
  }
}
