import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["modal", "content", "form"]

  connect() {
    this.userId = null
    this.userType = null
  }

  open(event) {
    event.preventDefault()

    const button = event.currentTarget
    this.userId = button.dataset.userId
    this.userType = button.dataset.userType

    this.fetchPermissions()
  }

  fetchPermissions() {
    const path = `/admin/${this.userType}/${this.userId}/get_permissions`

    fetch(path, {
      headers: { "Accept": "application/json" }
    })
      .then(response => {
        if (!response.ok) throw new Error("Network response was not ok")
        return response.json()
      })
      .then(data => this.renderPermissions(data))
      .catch(error => {
        console.error("Error fetching permissions:", error)
      })
  }

  renderPermissions(data) {
    const groupedPermissions = {}
    data.permissions.forEach(permission => {
      if (!groupedPermissions[permission.subject]) {
        groupedPermissions[permission.subject] = []
      }
      groupedPermissions[permission.subject].push(permission)
    })

    const permissionsHtml = Object.entries(groupedPermissions).map(([subject, permissions]) => {
      const groupId = subject.toLowerCase().replace(/\s+/g, '_')

      const groupItems = permissions.map(permission => {
        const isGroupPermission = data.group_permission_ids.includes(permission.id)
        const isChecked = isGroupPermission
          ? data.denied_permissions.includes(permission.id)
          : data.assigned_permissions.includes(permission.id)

        const labelTextColorClass = isGroupPermission
          ? 'text-red-600 dark:!text-red-400'
          : 'text-indigo-600 dark:!text-indigo-400'

        return `
          <div class="flex items-center py-2 px-3 border-b border-gray-300 dark:border-gray-600 hover:bg-gray-100 dark:hover:bg-gray-700 rounded transition-colors permission-item pl-10" data-subject="${groupId}">
            <input type="checkbox"
              name="${isGroupPermission ? 'denied_permission_ids[]' : 'permission_ids[]'}"
              value="${permission.id}"
              ${isChecked ? 'checked' : ''}
              class="h-5 w-5 border-gray-300 dark:border-gray-600 rounded mr-4 group-checkbox"
              data-group-id="${groupId}">
            <div class="flex-1">
              <div class="flex items-baseline">
                <span class="mr-2">${permission.name}</span>
                <small class="text-gray-600 dark:text-gray-400">(${permission.action} • ${permission.subject})</small>
              </div>
            </div>
            <span class="text-sm ${labelTextColorClass} font-medium">
              ${isGroupPermission ? 'Deny' : 'Allow'}
            </span>
          </div>
        `
      }).join('')

      return `
        <details class="mb-4 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded">
          <summary class="cursor-pointer px-4 py-3 font-semibold text-lg text-gray-800 dark:text-gray-200">
            ${subject} Permissions
          </summary>
          <div class="px-4 py-2 flex items-center space-x-2 pl-6">
            <input
              type="checkbox"
              name="select_all_${groupId}"
              data-action="change->permissions-modal#toggleGroup"
              data-group-id="${groupId}"
              class="h-5 w-5 border-gray-300 dark:border-gray-600 rounded"
            />
            <label class="text-base text-gray-700 dark:text-gray-300 font-medium">Full access to ${subject} management</label>
          </div>
          <div class="px-2 pb-2 text-base">
            ${groupItems}
          </div>
        </details>
      `
    }).join('')

    this.contentTarget.innerHTML = `
      <div class="max-h-[60vh] overflow-y-auto pr-2">
        ${permissionsHtml}
      </div>
    `

    // Sync group checkboxes with individual permissions
    Object.keys(groupedPermissions).forEach(subject => {
      const groupId = subject.toLowerCase().replace(/\s+/g, '_')
      const groupCheckbox = this.contentTarget.querySelector(`input[name="select_all_${groupId}"]`)
      if (!groupCheckbox) return

      const permissionCheckboxes = this.contentTarget.querySelectorAll(`.group-checkbox[data-group-id="${groupId}"]`)
      const allChecked = Array.from(permissionCheckboxes).every(cb => cb.checked)
      groupCheckbox.checked = allChecked
    })

    this.modalTarget.classList.remove("hidden")
  }

  toggleGroup(event) {
    const groupId = event.currentTarget.dataset.groupId
    const isChecked = event.currentTarget.checked

    const checkboxes = this.contentTarget.querySelectorAll(`.group-checkbox[data-group-id="${groupId}"]`)
    checkboxes.forEach(cb => {
      cb.checked = isChecked
    })
  }

  save(event) {
    event.preventDefault()

    const formData = new FormData(this.formTarget)

    // Capture current page from URL
    const urlParams = new URLSearchParams(window.location.search)
    const currentPage = urlParams.get('page') || 1
    formData.append('page', currentPage)

    fetch(`/admin/${this.userType}/${this.userId}/assign_permissions`, {
      method: 'POST',
      body: formData,
      headers: {
        'X-Requested-With': 'XMLHttpRequest',
        'Accept': 'text/vnd.turbo-stream.html',
        'X-CSRF-Token': document.querySelector('meta[name="csrf-token"]').content
      }
    })
      .then(response => response.text())
      .then(html => {
        Turbo.renderStreamMessage(html)
        this.close()
      })
      .catch(err => console.error("Error saving permissions:", err))
  }

  close() {
    this.modalTarget.classList.add("hidden")
    this.contentTarget.innerHTML = ""
    this.userId = null
    this.userType = null
  }
}
