document.addEventListener("DOMContentLoaded", () => {
  const flashNotice = document.querySelector(".bg-green-100.border-green-400.text-green-700");
  const flashAlert = document.querySelector(".bg-red-100.border-red-400.text-red-700");

  [flashNotice, flashAlert].forEach(flash => {
    if (flash) {
      setTimeout(() => {
        flash.style.transition = "opacity 0.5s ease-out";
        flash.style.opacity = "0";
        setTimeout(() => flash.remove(), 500);
      }, 2000);
    }
  });
});
