import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["fileInput", "submitBtn", "uploadedList", "modal", "dropZone", "modalTitle", "modalBody", "form"]
  static values = { editTitle: String, uploadTitle: String, currentPage: Number }

  allowedExtensions = ["jpg", "jpeg", "png", "pdf", "doc", "docx", "xls", "xlsx", "csv", "txt", "rtf", "heic"]

  connect() {
    this.files = []
    this.isEdit = false
  }

  // File handling
  openFileDialog() { this.fileInputTarget.click() }

  handleDrop(e) {
    e.preventDefault()
    this.dropZoneTarget.classList.remove("bg-neutral-100", "text-neutral-900", "dark:bg-neutral-700", "dark:text-neutral-100")
    this.addFiles(Array.from(e.dataTransfer.files))
  }

  handleDragOver(e) {
    e.preventDefault()
    this.dropZoneTarget.classList.add("bg-neutral-100", "text-neutral-900", "dark:bg-neutral-700", "dark:text-neutral-100")
  }

  handleDragLeave(e) {
    e.preventDefault()
    this.dropZoneTarget.classList.remove("bg-neutral-100", "text-neutral-900", "dark:bg-neutral-700", "dark:text-neutral-100")
  }

  handleFileSelect() { this.addFiles(Array.from(this.fileInputTarget.files)) }

  addFiles(newFiles) {
    const validFiles = Array.from(newFiles).filter(f => 
      this.allowedExtensions.includes(f.name.split(".").pop().toLowerCase())
    )

    if (!validFiles.length) {
      alert(`Only files of type: ${this.allowedExtensions.join(", ")} are allowed.`)
      return
    }

    this.files = this.isEdit ? validFiles.slice(0, 1) : 
      [...this.files, ...validFiles.filter(f => 
        !this.files.some(existing => existing.name === f.name && existing.size === f.size)
      )]
    
    this.syncFiles()
  }

  removeFile(e) {
    this.files.splice(e.currentTarget.dataset.index, 1)
    this.syncFiles()
  }

  syncFiles() {
    const data = new DataTransfer()
    this.files.forEach(f => data.items.add(f))
    this.fileInputTarget.files = data.files
    
    if (this.isEdit && this.hasFormTarget) {
      const formData = new FormData(this.formTarget)
      formData.delete('document[file]')
      if (this.files.length) formData.append('document[file]', this.files[0])
    }
    
    this.renderFileList()
    this.updateSubmitState()
  }

  renderFileList() {
    if (!this.hasUploadedListTarget) return
    this.uploadedListTarget.innerHTML = this.files.map((file, i) => `
      <li class="uploaded-image-name-list text-primary-600 font-semibold flex items-center gap-2 justify-between mb-2">
        <div class="flex items-center gap-2 flex-1 min-w-0">
          <iconify-icon icon="ph:link-break-light" class="text-xl text-secondary-light"></iconify-icon>
          <span class="truncate block whitespace-nowrap overflow-hidden text-ellipsis" title="${file.name}">${file.name}</span>
        </div>
        <span class="text-neutral-500 text-sm ml-2">${this.formatSize(file.size)}</span>
        <button type="button" class="text-red-600 hover:text-red-800 font-bold px-2 rounded ml-2 cursor-pointer"
          data-action="click->document-upload#removeFile" data-index="${i}">&times;</button>
      </li>
    `).join("")
  }

  updateSubmitState() {
    if (this.hasSubmitBtnTarget) this.submitBtnTarget.disabled = !this.files.length
  }

  formatSize(bytes) {
    const units = ['Bytes', 'KB', 'MB', 'GB']
    const i = Math.floor(Math.log(bytes) / Math.log(1024)) || 0
    return (bytes / Math.pow(1024, i)).toFixed(2) + ' ' + units[i]
  }

  // Modal handling
  openModal() {
    this.isEdit = false
    this.loadModalContent('new', this.uploadTitleValue || "Documents Upload")
  }

  openEditModal(e) {
    this.isEdit = true
    this.loadModalContent(`${e.currentTarget.dataset.documentId}/edit`, this.editTitleValue || "Document Edit")
  }

  loadModalContent(path, title) {
    if (this.hasModalTitleTarget) this.modalTitleTarget.textContent = title
    
    fetch(`/documents/${path}?page=${this.currentPageValue || 1}`)
      .then(res => res.ok ? res.text() : Promise.reject("Failed to load form"))
      .then(html => {
        this.modalBodyTarget.innerHTML = html
        if (this.isEdit && this.hasFormTarget) {
          this.formTarget.addEventListener('submit', this.handleFormSubmit.bind(this))
        }
        this.openModalUI()
      })
      .catch(console.error)
  }

  openModalUI() {
    this.modalTarget.classList.replace("hidden", "flex")
    document.body.classList.add("overflow-hidden")
  }

  closeModal() {
    this.modalTarget.classList.replace("flex", "hidden")
    document.body.classList.remove("overflow-hidden")
    this.files = []
    this.syncFiles()
  }

  // Form submission
  handleFormSubmit(e) {
    if (!this.isEdit || !this.files.length) return
    
    e.preventDefault()
    const formData = new FormData(this.formTarget)
    formData.delete('document[file]')
    formData.append('document[file]', this.files[0])

    fetch(this.formTarget.action, {
      method: 'PATCH',
      body: formData,
      headers: {
        'Accept': 'text/vnd.turbo-stream.html, text/html, application/xhtml+xml',
        'X-CSRF-Token': document.querySelector('meta[name="csrf-token"]').content
      }
    })
    .then(res => res.ok ? res.text() : Promise.reject('Network error'))
    .then(Turbo.renderStreamMessage)
    .catch(console.error)
  }

  // Loader
  showLoader() {
    this.closeModal()
    setTimeout(() => document.getElementById("loader")?.classList.remove("hidden"), 100)
  }

  hideLoader() {
    document.getElementById("loader")?.classList.add("hidden")
  }
}
