import { Controller } from "@hotwired/stimulus"
import { Turbo } from "@hotwired/turbo-rails"

export default class extends Controller {
  static targets = ["input", "submitButton", "fileInput", "filePreviewContainer", "filePreviews", "messagesContainer"]

  connect() {
    this.userScrolledUp = false
    this.lastScrollPosition = 0
    this.initializeScrollTracking()
    this.checkEmptyState()
  }

  initializeScrollTracking() {
    if (this.hasMessagesContainerTarget) {
      const observer = new MutationObserver(() => {
        this.scrollToBottomIfNotScrolledUp()
        this.checkEmptyState()
      })

      observer.observe(this.messagesContainerTarget, { childList: true, subtree: true })
      this.mutationObserver = observer

      if (this.isElementVisible(this.messagesContainerTarget)) {
        this.scrollToBottom({ behavior: 'auto' })
      } else {
        this.setupIntersectionObserver()
      }
    }
  }

  checkEmptyState() {
    const messages = this.messagesContainerTarget.querySelectorAll('[id^="message_"]')
    const noMessagesElement = this.messagesContainerTarget.querySelector('#no-messages')
    
    if (messages.length > 0 && noMessagesElement) {
      noMessagesElement.remove()
    }
  }

  setupIntersectionObserver() {
    this.observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting && !this.userScrolledUp) {
            this.scrollToBottom({ behavior: 'auto' })
          }
        })
      },
      { threshold: 0.1 }
    )
    this.observer.observe(this.messagesContainerTarget)
  }

  isElementVisible(element) {
    const rect = element.getBoundingClientRect()
    return (
      rect.top >= 0 &&
      rect.left >= 0 &&
      rect.bottom <= (window.innerHeight || document.documentElement.clientHeight) &&
      rect.right <= (window.innerWidth || document.documentElement.clientWidth)
    )
  }

  handleScroll(event) {
    const container = event.target
    const scrollTop = container.scrollTop
    const scrollHeight = container.scrollHeight
    const clientHeight = container.clientHeight

    this.userScrolledUp = scrollTop + clientHeight < scrollHeight - 100
    this.lastScrollPosition = scrollTop
  }

  initialize() {
    document.addEventListener('turbo:frame-load', (event) => {
      if (event.target.id === 'supervisor_message_blocks') {
        this.checkEmptyState()
        this.scrollToBottomIfNotScrolledUp()
      }
    })

    const originalRenderStreamMessage = Turbo.renderStreamMessage
    Turbo.renderStreamMessage = async function(streamMessage) {
      await originalRenderStreamMessage.call(this, streamMessage)

      requestAnimationFrame(() => {
        const controllerElement = document.querySelector('[data-controller="message"]')
        if (controllerElement) {
          const controller = controllerElement[this.identifier] || controllerElement.controller
          if (controller) {
            controller.checkEmptyState()
            controller.scrollToBottomIfNotScrolledUp()
          }
        }
      })
    }.bind(this)
  }

  scrollToBottomIfNotScrolledUp() {
    if (!this.userScrolledUp && this.hasMessagesContainerTarget) {
      requestAnimationFrame(() => {
        setTimeout(() => this.scrollToBottom({ behavior: 'auto' }), 50)
      })
    }
  }

  submitForm(event) {
    event.preventDefault()
    if (!this.hasContent()) return
    
    const formData = new FormData(this.element)
    
    fetch(this.element.action, {
      method: this.element.method,
      body: formData,
      headers: {
        'Accept': 'text/vnd.turbo-stream.html',
        'X-CSRF-Token': document.querySelector('[name="csrf-token"]').content
      }
    })
    .then(response => {
      if (response.ok) {
        this.clearForm()
        this.scrollToBottomIfNotScrolledUp()
      } else {
        this.showError()
      }
    })
    .catch(() => this.showError())
  }

  toggleSubmitButton() {
    this.submitButtonTarget.style.display = this.hasContent() ? 'flex' : 'none'
  }

  triggerFileInput() {
    this.fileInputTarget.click()
  }

  displayFilePreview() {
    if (this.fileInputTarget.files.length === 0) return
    
    this.filePreviewsTarget.innerHTML = Array.from(this.fileInputTarget.files)
      .map(file => this.createFilePreview(file))
      .join('')
    
    this.filePreviewContainerTarget.classList.remove('hidden')
    this.toggleSubmitButton()
  }

  hasContent() {
    return this.inputTarget.value.trim() || this.fileInputTarget.files.length > 0
  }

  clearForm() {
    this.inputTarget.value = ''
    this.clearAllFiles()
    this.toggleSubmitButton()
  }

  createFilePreview(file) {
    return `
      <div class="flex items-center gap-2 bg-white dark:bg-neutral-600 rounded-lg p-2 flex-shrink-0">
        ${file.type.startsWith('image/') ? 
          `<iconify-icon icon="heroicons:photo" class="text-4xl text-primary-600 dark:text-primary-400"></iconify-icon>` : 
          `<iconify-icon icon="heroicons:document" class="text-lg"></iconify-icon>`}
        <span class="text-sm truncate max-w-[100px]">${file.name}</span>
        <button type="button" class="text-neutral-500 dark:text-neutral-300 hover:text-red-500"
                data-action="click->message#removeFile" data-filename="${file.name}">
          <iconify-icon icon="heroicons:x-mark" class="text-sm"></iconify-icon>
        </button>
      </div>`
  }

  removeFile(event) {
    const fileName = event.target.closest('button').dataset.filename
    const dataTransfer = new DataTransfer()
    
    Array.from(this.fileInputTarget.files)
      .filter(file => file.name !== fileName)
      .forEach(file => dataTransfer.items.add(file))
    
    this.fileInputTarget.files = dataTransfer.files
    event.target.closest('div').remove()
    this.toggleSubmitButton()
    
    if (this.filePreviewsTarget.children.length === 0) {
      this.filePreviewContainerTarget.classList.add('hidden')
    }
  }

  clearAllFiles() {
    this.fileInputTarget.value = ''
    this.filePreviewsTarget.innerHTML = ''
    this.filePreviewContainerTarget.classList.add('hidden')
  }

  scrollToBottom(options = { behavior: 'smooth' }) {
    if (!this.hasMessagesContainerTarget) return

    const container = this.messagesContainerTarget
    requestAnimationFrame(() => {
      const bottomOffset = container.offsetHeight * 0.1
      container.scrollTo({
        top: container.scrollHeight + bottomOffset,
        ...options
      })
    })
  }

  showError() {
    const alert = document.createElement('div')
    alert.className = 'fixed top-4 right-4 bg-red-500 text-white px-4 py-2 rounded'
    alert.textContent = 'Failed to send message'
    document.body.appendChild(alert)
    setTimeout(() => alert.remove(), 3000)
  }
}