import { Controller } from "@hotwired/stimulus"

export default class extends Controller {
  static targets = ["assignSupervisorDeoModal", "chosenSupervisor", "chosenDeo", "assignButton"]
  
  setSupervisor(event) {
    event.preventDefault();
    const clientId = event.currentTarget.dataset.clientId;
    this.currentclientId = clientId;
    
    // Get existing assignments if any
    const supervisorId = event.currentTarget.dataset.supervisorId;
    const dataEntryOperatorId = event.currentTarget.dataset.dataEntryOperatorId;

    fetch('/managers/fetch_client_supervisors', {
      method: 'GET',
      headers: {
          Accept: 'application/json',
      },
    })
    .then(res => res.json())
    .then(data => {
      const html = data.html;
      this.assignSupervisorDeoModalTarget.innerHTML = html;
      this.assignSupervisorDeoModalTarget.classList.remove("hidden")

      if (supervisorId) {
        setTimeout(() => {
          this.chosenSupervisorTarget.value = supervisorId;
          this.changeSupervisor();
          
          if (dataEntryOperatorId) {
            setTimeout(() => {
              this.chosenDeoTarget.value = dataEntryOperatorId;
            }, 300);
          }
        }, 300);
      }
      
      this.updateAssignButtonState();
    })
    .catch(error => {
        console.error("error", error);
    });

  }

  changeSupervisor(event){
    const clientId = this.currentclientId;
    const supervisorId = event ? event.target.value : this.chosenSupervisorTarget.value;
    const dataEntryOperatorSelect = this.chosenDeoTarget
    dataEntryOperatorSelect.disabled = false

    dataEntryOperatorSelect.innerHTML = ""
    dataEntryOperatorSelect.disabled = true
    dataEntryOperatorSelect.classList.add('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400')
    dataEntryOperatorSelect.classList.remove('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white')

    if (!supervisorId) {
      const defaultOption = document.createElement("option")
      defaultOption.value = ""
      defaultOption.text = "Select Data Entry Operator (choose supervisor first)"
      dataEntryOperatorSelect.appendChild(defaultOption)
      this.updateAssignButtonState()
      return
    }


    fetch(`/managers/clients/${clientId}/supervisor_data_entry_operators?supervisor_id=${supervisorId}`, {
      headers: {
        "Accept": "application/json"
      }
    })
      .then(response => response.json())
      .then(data => {
        dataEntryOperatorSelect.innerHTML = ""

        if (data.length > 0) {
          const defaultOption = document.createElement("option")
          defaultOption.value = ""
          defaultOption.text = "Select Data Entry Operator"
          dataEntryOperatorSelect.appendChild(defaultOption)
        }

        data.forEach(operator => {
          const option = document.createElement("option")
          option.value = operator.id
          option.text = operator.name
          dataEntryOperatorSelect.appendChild(option)
        })

        if (data.length > 0) {
          dataEntryOperatorSelect.disabled = false
          dataEntryOperatorSelect.classList.remove('cursor-not-allowed', 'bg-gray-100', 'dark:bg-neutral-700', 'text-gray-500', 'dark:text-gray-400')
          dataEntryOperatorSelect.classList.add('cursor-pointer', 'bg-white', 'dark:bg-neutral-800', 'text-gray-900', 'dark:text-white')
        } else {
          const noOperatorsOption = document.createElement("option")
          noOperatorsOption.value = ""
          noOperatorsOption.text = "No data entry operators available"
          dataEntryOperatorSelect.appendChild(noOperatorsOption)
        }

        this.updateAssignButtonState();
      })
      .catch(error => {
        console.error("Error fetching data entry operators:", error)
      })
  }

  changeDataEntryOperator(){
    this.updateAssignButtonState()
  }

  allocate(event) {
    event.preventDefault();

    const deoIds = this.chosenDeoTarget.value;
    const supervisorIds = this.chosenSupervisorTarget.value;
    const apiUrl = `/managers/clients/${this.currentclientId}/assign_users`;
    
    // Get current page from URL or store it somewhere (or pass it explicitly)
    const urlParams = new URLSearchParams(window.location.search);
    const currentPage = urlParams.get('page') || 1;
    
    fetch(apiUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "text/html", // Expect HTML
        "X-CSRF-Token": document.querySelector("meta[name='csrf-token']").content
      },
      body: JSON.stringify({ supervisorIds: [supervisorIds], deoIds: [deoIds], page: currentPage })
    })
    .then(response => {
      if (response.redirected) {
        this.hideModal(); // Optionally hide modal first
        window.location.href = response.url; // Let browser fully navigate
      } else {
        throw new Error("Expected redirect response");
      }
    })
    .catch(error => {
      console.error("Error:", error);
    });
  }

  hideModal() {
    this.assignSupervisorDeoModalTarget.classList.add("hidden");
    this.updateAssignButtonState()
  }

  updateAssignButtonState() {
    const supervisorSelected = this.chosenSupervisorTarget.value !== "";
    const dataEntryOperatorSelected = this.chosenDeoTarget.value !== "";
    
    const hasSupervisors = this.chosenSupervisorTarget.querySelectorAll('option').length > 1;
    const hasDataEntryOperators = this.chosenDeoTarget.querySelectorAll('option').length > 1;
    
    const shouldEnable = !hasSupervisors ||
                        (supervisorSelected && !hasDataEntryOperators) ||
                        (supervisorSelected && dataEntryOperatorSelected);
    this.assignButtonTarget.disabled = !shouldEnable;
    
    if (shouldEnable) {
      this.assignButtonTarget.classList.remove('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
      this.assignButtonTarget.classList.add('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
    } else {
      this.assignButtonTarget.classList.remove('bg-blue-600', 'hover:bg-blue-700', 'cursor-pointer');
      this.assignButtonTarget.classList.add('bg-blue-500', 'dark:bg-blue-900', 'cursor-not-allowed');
    }
  }
}
