import { Controller } from "@hotwired/stimulus"
import * as Turbo from "@hotwired/turbo"

export default class extends Controller {
  static targets = ["selectAll", "checkbox", "bulkDropdownToggle", "bulkDropdownMenu", "dropdownArrow"]
  static values = { 
    url: String,
    currentPage: Number 
  }

  connect() {
    if (!this.hasSelectAllTarget || !this.hasBulkDropdownToggleTarget || !this.hasBulkDropdownMenuTarget || !this.urlValue) {
      console.warn('document_bulk_update_controller: missing required targets or URL');
      return;
    }

    this.boundToggleAllCheckboxes = this.toggleAllCheckboxes.bind(this);
    this.boundUpdateDropdownState = this.updateDropdownState.bind(this);
    this.boundToggleDropdownMenu = this.toggleDropdownMenu.bind(this);
    this.boundCloseDropdownMenu = this.closeDropdownMenu.bind(this);

    this.selectAllTarget.addEventListener('change', this.boundToggleAllCheckboxes);

    // Attach delegated event listener to the controller element
    this.element.addEventListener('change', (e) => {
      if (e.target.matches('input.document-checkbox')) {
        this.updateDropdownState();
      }
    });

    this.bulkDropdownToggleTarget.addEventListener('click', this.boundToggleDropdownMenu);

    this.updateDropdownState();
  }

  disconnect() {
    // Clean up all event listeners when the controller is disconnected
    this.selectAllTarget?.removeEventListener('change', this.boundToggleAllCheckboxes);
    this.checkboxTargets?.forEach(cb => cb.removeEventListener('change', this.boundUpdateDropdownState));
    this.bulkDropdownToggleTarget?.removeEventListener('click', this.boundToggleDropdownMenu);
    document.removeEventListener('click', this.boundCloseDropdownMenu);
  }

  toggleAllCheckboxes() {
    const checkboxes = this.checkboxTargets;
    const allChecked = checkboxes.every(cb => cb.checked);
    const someChecked = checkboxes.some(cb => cb.checked) && !allChecked;

    if (someChecked) {
      // In indeterminate state - first click should deselect all
      checkboxes.forEach(cb => cb.checked = false);
      this.selectAllTarget.checked = false;
      this.selectAllTarget.indeterminate = false;
    } else {
      // Not in indeterminate state - toggle all
      const newState = !allChecked;
      checkboxes.forEach(cb => cb.checked = newState);
      this.selectAllTarget.checked = newState;
      this.selectAllTarget.indeterminate = false;
    }
    
    this.updateDropdownState();
  }

  updateDropdownState() {
    const checkboxes = this.checkboxTargets;
    const selectedCount = checkboxes.filter(cb => cb.checked).length;
    const totalCount = checkboxes.length;

    this.bulkDropdownToggleTarget.disabled = selectedCount === 0;

    if (selectedCount === totalCount && totalCount > 0) {
      this.selectAllTarget.checked = true;
      this.selectAllTarget.indeterminate = false;
    } else if (selectedCount > 0) {
      this.selectAllTarget.checked = false;
      this.selectAllTarget.indeterminate = true;
    } else {
      this.selectAllTarget.checked = false;
      this.selectAllTarget.indeterminate = false;
    }

    if (selectedCount === 0) {
      this.bulkDropdownMenuTarget.classList.add("hidden");
      this.dropdownArrowTarget.classList.remove("rotate-180");
    }
  }

  toggleDropdownMenu(event) {
    event.stopPropagation();
    event.preventDefault();

    if (this.bulkDropdownToggleTarget.disabled) return;

    if (this.bulkDropdownMenuTarget.classList.contains("hidden")) {
      this.bulkDropdownMenuTarget.classList.remove("hidden");
      this.dropdownArrowTarget.classList.add("rotate-180");

      // Close the dropdown if clicking outside
      document.addEventListener('click', this.boundCloseDropdownMenu, { once: true });
    } else {
      this.bulkDropdownMenuTarget.classList.add("hidden");
      this.dropdownArrowTarget.classList.remove("rotate-180");
    }
  }

  closeDropdownMenu(event) {
    if (!this.element.contains(event.target)) {
      this.bulkDropdownMenuTarget.classList.add("hidden");
      this.dropdownArrowTarget.classList.remove("rotate-180");
    }
  }

  async selectStatus(event) {
    const status = event.currentTarget.dataset.status;
    event.preventDefault();

    const selectedDocumentIds = this.checkboxTargets
      .filter(cb => cb.checked)
      .map(cb => cb.value);

    if (selectedDocumentIds.length === 0 || !status) {
      return;
    }

    const urlWithPage = `${this.urlValue}?page=${this.currentPageValue}`;

    try {
      const response = await fetch(urlWithPage, {
        method: 'PATCH',
        headers: {
          'Accept': 'text/vnd.turbo-stream.html, application/json',
          'Content-Type': 'application/json',
          'X-CSRF-Token': document.querySelector('[name="csrf-token"]').content
        },
        body: JSON.stringify({
          document_ids: selectedDocumentIds,
          status: status
        })
      });

      const contentType = response.headers.get("content-type");

      if (response.ok) {
        if (contentType && contentType.includes("text/vnd.turbo-stream.html")) {
          const turboStream = await response.text();
          Turbo.renderStreamMessage(turboStream);
          // After Turbo Stream updates, manually update the dropdown state
          setTimeout(() => {
            this.updateDropdownState();
          }, 10); // Small delay to ensure DOM is updated
        } else if (contentType && contentType.includes("application/json")) {
          const data = await response.json();
          if (data.status === 'success') {
            location.reload();
          } else {
            alert(data.error);
          }
        }
      } else {
        const data = await response.json();
        alert(data.error);
      }
    } catch (err) {
      console.error(err);
    } finally {
      // Close dropdown after update
      this.bulkDropdownMenuTarget.classList.add("hidden");
      this.dropdownArrowTarget.classList.remove("rotate-180");
    }
  }
}
