import { Controller } from "@hotwired/stimulus"

export default class extends Controller {
  static targets = ["assignDeoModal", "assignDeoModalChosenDeo"]

  connect() {
    console.log("Assign Deo Controller connected");
  }

  setClient(event) {
    console.log("Set client triggered");
    event.preventDefault();
    const clientId = event.currentTarget.dataset.clientId;
    const currentDeoId = event.currentTarget.dataset.currentDeoId;

    this.assignDeoModalTarget.dataset.clientId = clientId;

    event.currentTarget.dataset.currentDeoId = currentDeoId;

    if (currentDeoId) {
      this.assignDeoModalChosenDeoTarget.value = currentDeoId;
    } else {
      this.assignDeoModalChosenDeoTarget.value = "";
    }

    this.showModal();
  }

  async allocate(event) {
    event.preventDefault();

    const clientId = this.assignDeoModalTarget.dataset.clientId;
    const deoIds = [this.assignDeoModalChosenDeoTarget.value];
    const clientRow = document.querySelector(`tr[data-entry-operator-id="${clientId}"]`);
    const deoCell = clientRow.querySelector('td:nth-child(3)');
    const assignButton = clientRow.querySelector('[data-action="click->supervisors--assign-deo#setClient"]');

    try {
      const response = await fetch(`/supervisors/clients/${clientId}/assign_deos`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "X-CSRF-Token": document.querySelector("meta[name='csrf-token']").content,
          "Accept": "application/json"
        },
        body: JSON.stringify({ deo_ids: deoIds })
      });

      if (response.ok) {
        const data = await response.json();
        if (data.success) {
          if (data.deo_names && data.deo_names.length > 0) {
            deoCell.innerHTML = data.deo_names.join(", ");
          } else {
            deoCell.innerHTML = '<span class="text-gray-400">-</span>';
          }

          if (assignButton) {
            assignButton.dataset.currentDeoId = deoIds[0] || "";
          }

          this.showFlashMessage('success', 'Data Entry Operator assigned successfully!');
        }
      } else {
        throw new Error("Assignment failed");
      }
    } catch (error) {
      console.error("Error:", error);
      this.showFlashMessage('error', 'Failed to assign Data Entry Operator');
    } finally {
      this.hideModal();
    }
  }

  showModal() {
    this.assignDeoModalTarget.classList.remove("hidden");
    document.body.classList.add("overflow-hidden");
  }

  hideModal() {
    this.assignDeoModalTarget.classList.add("hidden");
    document.body.classList.remove("overflow-hidden");
  }
}